import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office — quote (base premiums, single item)", () => {
  // Edge case: empty item list
  it.todo("empty item list → premium 5 G (only the processing fee)");

  // Base premiums for main items (newcomer: 0 years, first insurance applies)
  // Note: with first-insurance 10% and 5 G fee, but tests below isolate base where possible.
  it.todo("single sword (0 yrs) → 100 base +10 first +5 fee = 115 G");
  it.todo("single amulet (0 yrs) → 60 base +6 first +5 fee = 71 G");
  it.todo("single staff (0 yrs) → 80 base +8 first +5 fee = 93 G");
  it.todo("single potion (0 yrs) → 40 base +4 first +5 fee = 49 G");
});

describe("MHPCO Claim Office — quote (component blocks)", () => {
  it.todo("2 runes → 50 G base premium (no block)");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium");
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
});

describe("MHPCO Claim Office — quote (item-specific modifiers)", () => {
  it.todo("cursed sword adds 50% surcharge to that item's base premium");
  it.todo("sword with enchantment exactly 5 → high-enchantment 30% surcharge applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
  it.todo("every item in a quote is treated as first insurance (10% surcharge) regardless of customer history");
});

describe("MHPCO Claim Office — quote (policy-wide modifiers)", () => {
  it.todo("customer with exactly 2 years → 20% loyalty discount applies on policy base premium");
  it.todo("customer with <2 years → no loyalty discount");
  it.todo("each contract after the first → 15% follow-up discount on policy base premium");
  it.todo("first contract → no follow-up discount");
});

describe("MHPCO Claim Office — quote (modifier scope on multi-item policies)", () => {
  it.todo("cursed sword (100) + plain amulet (60) → base 160, curse adds 50 (50% of sword only) → 210 before further modifiers and fee");
});

describe("MHPCO Claim Office — quote (rounding)", () => {
  it.todo("premium calc yielding 197.5 G → 198 G (rounded up in MHPCO favor)");
});

describe("MHPCO Claim Office — quote (integration examples)", () => {
  it.todo("newcomer cursed sword (0 yrs, steel, ench 3) → 100 +50 curse +10 first +5 fee = 165 G");
  it.todo("long-standing 2nd contract cursed sword (3 yrs, ench 7) → 100 +50 curse +30 high-ench -20 loyalty +10 first -15 follow-up +5 fee = 160 G");
});

describe("MHPCO Claim Office — claim (standard reimbursement)", () => {
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (500 - 100 deductible)");
  it.todo("rune (value 250), damage 200 → payout 100 (200 - 100 deductible; no special clause)");
});

describe("MHPCO Claim Office — claim (special clauses)", () => {
  it.todo("steel sword ench 9, damage 1000 → payout 400 (50% = 500, then -100 deductible)");
  it.todo("dragon-material sword ench 5, damage 800 → payout 700 (full reimbursement, then -100 deductible)");
  it.todo("dragon-material sword ench 9, damage 1000 → payout 400 (50% wins, then -100 deductible)");
  it.todo("dragon-material sword ench exactly 8, damage 1000 → payout 400 (high-ench clause then deductible)");
});

describe("MHPCO Claim Office — claim (deductible per damage event)", () => {
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");
});

describe("MHPCO Claim Office — claim (multiple items of the same type)", () => {
  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
  it.todo("dragon attack damages both swords (two sword entries) → each treated as separate damage with own deductible");
  it.todo("more damage entries of a type than insured (two sword damages, one sword) → claim rejected (throws)");
});

describe("MHPCO Claim Office — claim (cap)", () => {
  it.todo("sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword → cap 2000 (based on unmodified insurance value; premium modifiers do not raise cap)");
  it.todo("sword + 3 runes block → insurance sum 1750 (block discount affects premium only, not insurance sum)");
  it.todo("sword (cap 2000), two successive 1500 claims → first payout 1400 (remaining 600), second payout 600 (remaining 0)");
});

describe("MHPCO Claim Office — claim (rounding)", () => {
  it.todo("payout calc yielding 350.5 G → 350 G (rounded down in MHPCO favor)");
});

describe("MHPCO Claim Office — claim (errors)", () => {
  it.todo("claim references item not in policy (amulet damaged, only sword insured) → throws");
  it.todo("damage entry with amount -200 → throws");
});

describe("MHPCO Claim Office — quote (errors)", () => {
  it.todo("quote includes unknown item type (broomstick) → throws");
});

