export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

const PROCESSING_FEE = 5;

export const quote = (
  items: Item[],
  customer: Customer,
  contractIndex: number,
): number => {
  return PROCESSING_FEE;
};

export const claim = (): number => {
  return undefined as unknown as number;
};

export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

const PROCESSING_FEE = 5;

export const quote = (
  items: Item[],
  customer: Customer,
  contractIndex: number,
): number => {
  let policyBase = 0;
  for (const item of items) {
    const base = 100; // sword base premium
    policyBase += base * 1.1; // first-insurance surcharge
  }
  return policyBase + PROCESSING_FEE;
};

export const claim = (): number => {
  return undefined as unknown as number;
};

export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
