export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

const PROCESSING_FEE = 5;
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};
const FIRST_INSURANCE_MULTIPLIER = 1.1;

const COMPONENT_TYPES = ["rune"];
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const isComponent = (item: Item): boolean =>
  COMPONENT_TYPES.includes(item.type);

// Base premium for `count` alike components: every full block of 3 costs
// the special block premium; leftover components are priced individually.
const componentBasePremium = (count: number): number => {
  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
  const remainder = count % COMPONENT_BLOCK_SIZE;
  return blocks * COMPONENT_BLOCK_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;
};

// Round up in MHPCO's favour, guarding against floating-point noise
// (e.g. 197.50000000001 should still round to 198, not 199).
const roundUpInMHPCOFavor = (amount: number): number =>
  Math.ceil(Number(amount.toFixed(6)));

export const quote = (
  items: Item[],
  customer: Customer,
  contractIndex: number,
): number => {
  const mainItems = items.filter((item) => !isComponent(item));
  const componentCount = items.length - mainItems.length;

  const mainBase = mainItems.reduce(
    (sum, item) => sum + BASE_PREMIUMS[item.type] * FIRST_INSURANCE_MULTIPLIER,
    0,
  );
  const componentBase =
    componentBasePremium(componentCount) * FIRST_INSURANCE_MULTIPLIER;

  return roundUpInMHPCOFavor(mainBase + componentBase + PROCESSING_FEE);
};

export const claim = (): number => {
  return undefined as unknown as number;
};

