export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface Policy {
  items: Item[];
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

const DEDUCTIBLE_PER_EVENT = 100;

// A single damage's reimbursement: its amount net of the per-event deductible.
const damageReimbursement = (damage: Damage): number =>
  damage.amount - DEDUCTIBLE_PER_EVENT;

export const claim = (
  policy: Policy,
  incident: Incident,
  capRemaining: number,
): ClaimResult => {
  const payout = roundDownInMHPCOFavor(
    sum(incident.damages.map(damageReimbursement)),
  );
  return { payout, remainingCap: capRemaining - payout };
};

