const DEDUCTIBLE_PER_EVENT = 100;
const ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
const ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;

// A single damage's reimbursement: the reimbursed amount net of the per-event
// deductible. Highly enchanted items (enchantment >= 8) are reimbursed at 50%
// of the damage before the deductible.
const damageReimbursement = (damage: Damage, policy: Policy): number => {
  const item = policy.items.find((i) => i.type === damage.itemType);
  const reimbursed =
    item && (item.enchantment ?? 0) >= ENCHANTMENT_REIMBURSEMENT_THRESHOLD
      ? ENCHANTMENT_REIMBURSEMENT_RATE * damage.amount
      : damage.amount;
  return reimbursed - DEDUCTIBLE_PER_EVENT;
};

export const claim = (
  policy: Policy,
  incident: Incident,
  capRemaining: number,
): ClaimResult => {
  const payout = roundDownInMHPCOFavor(
    sum(incident.damages.map((damage) => damageReimbursement(damage, policy))),
  );
  return { payout, remainingCap: capRemaining - payout };
};

