// The insured item a damage refers to, looked up by type from the policy.
const insuredItemFor = (damage: Damage, policy: Policy): Item | undefined =>
  policy.items.find((item) => item.type === damage.itemType);

// A single damage's reimbursement: the covered amount net of the per-event
// deductible. The covered amount is the full damage, except for highly
// enchanted items, which are covered at ENCHANTMENT_REIMBURSEMENT_RATE.
const damageReimbursement = (damage: Damage, policy: Policy): number => {
  const item = insuredItemFor(damage, policy);
  const rate =
    item && isHighlyEnchanted(item)
      ? ENCHANTMENT_REIMBURSEMENT_RATE
      : FULL_REIMBURSEMENT_RATE;
  return rate * damage.amount - DEDUCTIBLE_PER_EVENT;
};

export const claim = (
  policy: Policy,
  incident: Incident,
  capRemaining: number,
): ClaimResult => {
  const payout = roundDownInMHPCOFavor(
    sum(incident.damages.map((damage) => damageReimbursement(damage, policy))),
  );
  return { payout, remainingCap: capRemaining - payout };

